const s=`{% block sw_settings_media_index %} <sw-page class="sw-settings-media"> {% block sw_settings_media_header %} <template #smart-bar-header> <h2>{{ $t('sw-settings.index.title') }} <mt-icon name="regular-chevron-right-xs" size="12px" /> {{ $t('sw-settings-media.general.title') }} </h2> </template> {% endblock %} {% block sw_settings_media_smart_bar_actions %} <template #smart-bar-actions> {% block sw_settings_media_actions_save %} <sw-button-process class="sw-settings-media__save-action" :is-loading="isLoading" :process-success="isSaveSuccessful" :disabled="isLoading" variant="primary" @update:process-success="saveFinish" @click="onSave" > {{ $t('sw-settings-media.general.buttonSave') }} </sw-button-process> {% endblock %} </template> {% endblock %} {% block sw_settings_media_content %} <template #content> <sw-card-view> <template v-if="isLoading"> <sw-skeleton /> <sw-skeleton /> </template> <sw-system-config v-show="!isLoading" ref="systemConfig" domain="core.media" @loading-changed="onLoadingChanged" /> </sw-card-view> </template> {% endblock %} </sw-page> {% endblock %}`,{Mixin:t}=Shopware,i={template:s,inject:["systemConfigApiService"],mixins:[t.getByName("notification")],data(){return{isLoading:!1,isSaveSuccessful:!1}},metaInfo(){return{title:this.$createTitle()}},created(){this.createdComponent()},methods:{async createdComponent(){this.isLoading=!0},saveFinish(){this.isSaveSuccessful=!1},onSave(){this.isSaveSuccessful=!1,this.isLoading=!0,this.$refs.systemConfig.saveAll().then(()=>{this.isLoading=!1,this.isSaveSuccessful=!0}).catch(e=>{this.isLoading=!1,this.createNotificationError({message:e})})},onLoadingChanged(e){this.isLoading=e}}};export{i as default};
